	switch packet.Type {
	case message.TypeNewPeer, message.TypeChatMsg:
 s.messagesChan <- packet
	case message.TypePeerList, message.TypeSenderKey:

 targetConn, exists := s.getPeerConn(packet.TargetPeer)
