Основной код клиента
package client

import (
	"bufio"
	"encoding/json"
	"fmt"
	"log"
	"net"
	"os"

	cryptography "github.com/barashF/TCP-chat/crypto"
	"github.com/barashF/TCP-chat/message"
	processedpacket "github.com/barashF/TCP-chat/processed_packet"
)

type P2PKeys struct {
	SecretECDH []byte
	AES []byte
}

type ClientChat struct {
	Address string
	Conn net.Conn
	Keys cryptography.CryptoKeys
	TopologyTable map[string]P2PKeys
}

func NewClientChat(Addr string) *ClientChat {
	return &ClientChat{
 Address: Addr,
 Keys: *cryptography.GenerateClientsCrypto(),
 TopologyTable: make(map[string]P2PKeys),
	}
}

func (c *ClientChat) Start() {
	var err error
	c.Conn, err = net.Dial("tcp", c.Address)
	if err != nil {
 log.Fatal("Failed connection: %w", err)
	}
	defer c.Conn.Close()

	c.enterToChat()
	go c.readLoop()

	scanner := bufio.NewScanner(os.Stdin)
	for scanner.Scan() {
 text := scanner.Text()
 if text == "" {
 continue
 }

 msg, _ := json.Marshal(message.Message{
 Text: text,
 })

 encryptMsg, _ := cryptography.EncryptMessage(c.Keys.AESKey, msg)
 packet := message.Packet{
 Type: message.TypeChatMsg,
 Message: encryptMsg,
 }
 if err := c.sendMessage(packet); err != nil {
 log.Printf("failed send message: %v", err)
 break
 }
	}

	if err := scanner.Err(); err != nil {
 log.Printf("Failed read from console: %v", err)
	}
}

func (c *ClientChat) readLoop() {
	scanner := bufio.NewScanner(c.Conn)
	for scanner.Scan() {
 var packet message.Packet
 if err := json.Unmarshal(scanner.Bytes(), &packet); err != nil {
 log.Printf("Error parsing packet: %v", err)
 continue
 }

 c.processPacket(packet)
	}
}

func (c *ClientChat) processPacket(packet message.Packet) error {
	switch packet.Type {

	case message.TypeNewPeer:
 if packet.FromPeer == packet.YourName {
 c.addAES(packet.FromPeer, c.Keys.AESKey)
 return nil
 }

 fmt.Printf(" [System]: User %s enter to chat.\n", packet.FromPeer)
 sendKeyPacket := processedpacket.ProcessedNewPeer(packet, c.Keys.PrivateECDHKey, c.Keys.AESKey)

 secretECDH := cryptography.GenarateECDHSecret(c.Keys.PrivateECDHKey, packet.PublicKey)
 c.addECDH(packet.FromPeer, secretECDH)

 c.sendMessage(*sendKeyPacket)

	case message.TypeSenderKey:
 peerKeys := c.getP2PKeys(packet.FromPeer)
 aesKey, err := cryptography.DecryptSenderKey(peerKeys.SecretECDH, packet.EncAESKey)
 if err != nil {
 log.Printf("Failed decrypt aes: %v", err)
 return err
 }

 c.addAES(packet.FromPeer, aesKey)

	case message.TypeChatMsg:
 keys := c.getP2PKeys(packet.FromPeer)

 decryptMessage, _ := cryptography.DecryptMessage(keys.AES, packet.Message)

 var msg message.Message
 if err := json.Unmarshal(decryptMessage, &msg); err != nil {
 log.Printf("Failed decode message: %v\n", err)
 return err
 }
 fmt.Printf("[%s]: %s\n", packet.FromPeer, msg.Text)

	case message.TypePeerList:
 c.createTopologyTable(packet.Peers)
 c.BroadcastAES()

	default:
 log.Printf("incorrect packet type: %s", packet.Type)
 return fmt.Errorf("incorrect packet type: %s", packet.Type)
	}

	return nil
}

func (c *ClientChat) BroadcastAES() {
	for peer, data := range c.TopologyTable {
 encryptedAES := cryptography.EncryptAESKey(data.SecretECDH, c.Keys.AESKey)
 packet := processedpacket.CreateSenderKeyPacket(encryptedAES, peer)

 c.sendMessage(*packet)
	}
}

func (c *ClientChat) createTopologyTable(peers []message.PeerInfo) {
	for _, peer := range peers {
 secret := cryptography.GenarateECDHSecret(c.Keys.PrivateECDHKey, peer.PublicKey)
 c.addECDH(peer.Nickname, secret)
	}
}

func (c *ClientChat) enterToChat() {
	helloPacket := processedpacket.NewPeerPacket(c.Keys.PublicECDHKey)
	c.sendMessage(*helloPacket)
}

func (c *ClientChat) sendMessage(packet message.Packet) error {
	packetBytes, err := json.Marshal(packet)
	if err != nil {
 return err
	}
	_, err = fmt.Fprintf(c.Conn, "%s\n", packetBytes)
	return err
}

func (c *ClientChat) getTopologyTable() {
	packet := message.Packet{
 Type: message.TypeGetPeerList,
	}
	c.sendMessage(packet)
}

func (c *ClientChat) getP2PKeys(user string) P2PKeys {
	keys, exists := c.TopologyTable[user]
	if !exists {
 c.getTopologyTable()
 keys = c.TopologyTable[user]
	}
	return keys
}

func (c *ClientChat) addECDH(user string, ecdhKey []byte) {
	keys := c.TopologyTable[user] // если нет, вернется пустая структура
	keys.SecretECDH = ecdhKey
	c.TopologyTable[user] = keys
}

func (c *ClientChat) addAES(user string, aesKey []byte) {
	userKeys, exists := c.TopologyTable[user]
	if !exists {
 userKeys = P2PKeys{}
	}

	userKeys.AES = aesKey
	c.TopologyTable[user] = userKeys
}
Код сервера
package server

import (
	"context"
	"encoding/json"
	"fmt"
	"log"
	"net"
	"os/signal"
	"sync"
	"syscall"
	"time"

	"github.com/barashF/TCP-chat/message"
)

type Peer struct {
	Conn net.Conn
	PublicKey []byte
	ConnectedAt time.Time
}

type Server struct {
	Address string
	Listener net.Listener
	clients map[string]*Peer
	deadClients []net.Conn
	mu sync.RWMutex
	messagesChan chan message.Packet
}

func NewServer(address string) *Server {
	return &Server{
 Address: address,
 messagesChan: make(chan message.Packet, 100),
 clients: make(map[string]*Peer),
 deadClients: make([]net.Conn, 0),
	}
}

func (s *Server) Start() error {
	var err error
	s.Listener, err = net.Listen("tcp", s.Address)
	if err != nil {
 log.Printf("Error accept: %v", err)
 return err
	}

	log.Printf("Server started")

	ctx, cancel := signal.NotifyContext(context.Background(), syscall.SIGINT, syscall.SIGTERM)
	go s.acceptLoop(ctx)
	go s.Broadcast(ctx)
	defer func() {
 cancel()
 s.Listener.Close()
 close(s.messagesChan)
	}()
	s.Stop(ctx)
	return nil
}

func (s *Server) acceptLoop(ctx context.Context) {
	for {

 conn, err := s.Listener.Accept()
 if err != nil {
 select {
 case <-ctx.Done():
 log.Println("Accept loop stopped")
 return
 default:
 log.Printf("Failed accept client: %v", err)
 }
 }
 log.Printf("Welcome, %s", conn.RemoteAddr().String())
 go s.handleConn(conn)
	}
}

func (s *Server) handleConn(conn net.Conn) {
	defer conn.Close()

	err := s.handshake(conn)
	if err != nil {
 return
	}

	buf := make([]byte, 2048)
	for {
 n, err := conn.Read(buf)
 if err != nil {
 log.Printf("Connection error: %v", err)
 return
 }

 var packet message.Packet
 err = json.Unmarshal(buf[:n], &packet)
 if err != nil {
 log.Printf("Failed encoding packet: %v", err)
 continue
 }

 packet.FromPeer = conn.RemoteAddr().String()

 s.processPacket(packet)
	}
}

func (s *Server) handshake(conn net.Conn) error {
	if _, exists := s.clients[conn.RemoteAddr().String()]; exists {
 conn.Close()
 return fmt.Errorf("user already connection")
	}

	buf := make([]byte, 2048)
	n, err := conn.Read(buf)
	if err != nil {
 log.Printf("Handshake error: %v", err)
 return fmt.Errorf("failed handshake: %w", err)
	}

	var packet message.Packet
	err = json.Unmarshal(buf[:n], &packet)
	if err != nil {
 log.Printf("Handshake error: %v", err)
 return fmt.Errorf("failed handshake: %v", err)
	}

	if packet.Type != message.TypeAuth {
 log.Printf("Incorrect type packet")
 return fmt.Errorf("client hello packet need auth type")
	}

	s.registerPeer(conn, packet.PublicKey)

	packet.Type = message.TypeNewPeer
	packet.FromPeer = conn.RemoteAddr().String()
	s.processPacket(packet)

	packetListPeers := s.generatePacketListPeers(conn.RemoteAddr().String())
	s.processPacket(*packetListPeers)

	return nil
}

func (s *Server) generatePacketListPeers(target string) *message.Packet {
	var packet message.Packet

	packet.TargetPeer = target
	packet.Type = message.TypePeerList

	peersInfo := make([]message.PeerInfo, 0, len(s.clients))
	s.mu.Lock()
	for peer, data := range s.clients {
 if peer != target {
 peersInfo = append(peersInfo, message.PeerInfo{
 Nickname: peer,
 PublicKey: data.PublicKey,
 })
 }
	}
	s.mu.Unlock()

	packet.Peers = peersInfo

	return &packet
}

func (s *Server) Broadcast(ctx context.Context) {
	for {
 select {
 case <-ctx.Done():
 return
 case msg := <-s.messagesChan:
 s.mu.RLock()
 for _, client := range s.clients {
 s.writeInConnection(client.Conn, msg)
 }
 s.mu.RUnlock()
 for _, conn := range s.deadClients {
 s.unregisterPeer(conn)
 }
 s.deadClients = s.deadClients[:0]
 }
	}
}

func (s *Server) writeInConnection(conn net.Conn, message message.Packet) {
	message.YourName = conn.RemoteAddr().String()

	msgBytes, err := json.Marshal(message)
	if err != nil {
 log.Printf("Failed to marshal JSON: %v", err)
 return
	}

	payload := fmt.Sprintf("%s\n", string(msgBytes))
	_, err = conn.Write([]byte(payload))
	if err != nil {
 log.Printf("Failed write message: %v", err)
 s.deadClients = append(s.deadClients, conn)
	}
}

func (s *Server) processPacket(packet message.Packet) error {
	switch packet.Type {
	case message.TypeNewPeer, message.TypeChatMsg:
 s.messagesChan <- packet

	case message.TypePeerList, message.TypeSenderKey:

 targetConn, exists := s.getPeerConn(packet.TargetPeer)
 if !exists {
 log.Printf("not found target connection")
 return fmt.Errorf("not found target connection")
 }
 s.writeInConnection(targetConn, packet)
	case message.TypeGetPeerList:
 packetList := s.generatePacketListPeers(packet.FromPeer)
 targetConn, exists := s.getPeerConn(packet.TargetPeer)
 if !exists {
 log.Printf("not found target connection")
 return fmt.Errorf("not found target connection")
 }
 s.writeInConnection(targetConn, *packetList)

	default:
 return fmt.Errorf("incorrect packet type")
	}

	return nil
}

func (s *Server) registerPeer(conn net.Conn, publicKey []byte) {
	peer := &Peer{
 Conn: conn,
 PublicKey: publicKey,
 ConnectedAt: time.Now(),
	}

	s.mu.Lock()
	defer s.mu.Unlock()
	s.clients[conn.RemoteAddr().String()] = peer
}

func (s *Server) unregisterPeer(conn net.Conn) {
	s.mu.Lock()
	defer s.mu.Unlock()
	conn.Close()
	delete(s.clients, conn.RemoteAddr().String())
	log.Printf("Client disconnected: %s", conn.RemoteAddr().String())
}

func (s *Server) getPeerConn(peer string) (net.Conn, bool) {
	s.mu.RLock()
	defer s.mu.RUnlock()

	conn, exists := s.clients[peer]

	return conn.Conn, exists
}

func (s *Server) Stop(ctx context.Context) {
	<-ctx.Done()
	for _, client := range s.clients {
 s.unregisterPeer(client.Conn)
	}
}
Заключение
Мы успешно реализовали честное End-to-End шифрование для нашего TCP-чата. Да, наш сервер всё еще координирует сеть и пересылает пакеты (выполняет роль сигнального сервера и роутера), но он больше не имеет доступа к самим сообщениям. Как видно из логов, попытка сервера десериализовать сообщение падает с ошибкой — для него это просто массив случайных байт.
Мы построили гибридную схему:
ECDH на кривой X25519 безопасно связал клиентов и помог им выработать общий секрет без риска перехвата.
AES-256 в режиме GCM взял на себя тяжелую работу по шифрованию больших потоков текста и гарантировал, что никто не сможет изменить байты сообщения в процессе транзита.
Что дальше?
Наш чат стал приватным, но пока не стал по-настоящему надежным и безопасным от более изощренных атак. В следующих статьях мы разберем:
Защиту от MITM (Man-in-the-Middle): Сервер не может прочитать сообщения, но что мешает вредоносному серверу подменить публичные ключи участников в момент рукопожатия и читать всё? Будем решать проблему доверия к ключам.
Аутентификацию пользователей: Добавим полноценную сессию, подписи пакетов и разберемся, как привязать постоянный профиль пользователя к его временным сессионным ключам.

Привет! Меня зовут Александр, я разработчик в
Битрикс24
.
Заметил такую особенность во многих учебных статьях и туториалах: в популярных объяснениях паттернов часто не хватает оговорки, что ради упрощения объяснения в примере нарушены принципы
SOLID
.
Почему так: многие из примеров решают задачу обучения, а не задачу проектирования архитектуры. То есть примеры часто короткие и удобные для объяснения, но иногда вместе с этим они теряют важные свойства самого паттерна.
Особенно часто это происходит с
Factory Method
. В этой статье мы разберём несколько популярных примеров этого паттерна, посмотрим, где именно возникает проблема, и обсудим альтернативы в реальных проектах.
Чтобы дальше не путаться в терминах, сначала коротко зафиксируем, что такое принцип
OCP
: программные сущности должны быть открыты для расширения, но закрыты для изменения. Проще говоря, если завтра в системе появляется новый тип объекта, нам хотелось бы добавить новый класс и подключить его к системе, а не переписывать уже работающий код в нескольких местах.
Примеры для разбора
Ниже несколько материалов, где фабрика или Factory Method объясняются через выбор реализации по строке, switch, match или похожую центральную развилку. Такие примеры полезны как материал для разбора: внешне они выглядят как паттерн, но при добавлении нового типа часто требуют менять уже существующую фабрику.
JavaRush: Паттерн проектирования Factory
— пример, с которого начался этот разбор.
Quipoin: Factory Method Design Pattern in Java with Real Example
— пример NotificationFactory с выбором через switch.
MagicBell: Notification System Design
— пример NotificationFactoryImpl с switch(type) и заявленным OCP.
JavaGuides: Java Factory Pattern with Real-World Examples
— показано нарушение OCP через if/else, а затем фабрика со switch.
MakeDev: Фабричный метод на PHP
— русскоязычный пример с FactoryAbstract::create($type) и switch.
PHPLex: Factory Pattern
— PHP-пример с enum и match.
ndup.io
: Factory Pattern in Python
— пример NotificationFactory.create_notifier() через if/elif.
LIG: PHP Factory Pattern
— пример, где проблема switch обсуждается, но похожая развилка остается в фабриках.
Christopher Okhravi: Factory Method Pattern
— полезно как контрастное объяснение разницы между Simple Factory и Factory Method.
Все примеры выглядят довольно разумно. Проблема становится заметна не в первой версии кода, а позже, когда система начинает расти.
Важно: проблема не в фабричном методе как паттерне, а в примерах, где фабрикой называют обычный
create($type)
с набором
if
/
elseif
. Такая фабрика нарушает принцип
Open/Closed Principle (OCP)
, потому что к новый тип объекта требует возвращаться в уже существующую фабрику и изменять её.
Пример с нарушением SOLID (OCP)
class ProductFactory
{
 public function create(string $type): Product
 {
 if ($type === 'car') {
 return new Car();
 } elseif ($type === 'bike') {
 return new Bike();
 }

 throw new InvalidArgumentException('Unknown type');
 }
}
В чем тут проблема? Допустим, у нас появился еще один продукт:
class Truck implements Product {}
Тогда чтобы его добавить в фабрику нам нужно будет залезть в этот метод и добавить в него такой код:
elseif ($type === 'truck') { 
 return new Truck(); 
}
И это нарушает принцип открытости/закрытости (
OCP
).
Проблема в примере выше в том, что под «фабрикой» здесь фактически скрывается большой оператор выбора. Если заменить
if
/
elseif
на
switch
или
match
, архитектурная проблема не исчезнет. Изменится только синтаксис.
Пример NotificationFactory
Пример с автомобилями хорошо показывает нарушение
OCP
, но выглядит немного искусственно. В реальных проектах фабрики чаще встречаются при работе с интеграциями, платёжными системами, обработчиками событий.
Следующий пример с нарушением чуть ближе к реальным задачам:
interface Notification
{
 public function send(): void;
}
class NotificationFactory
{
 public function create(string $type): Notification
 {
 if ($type === 'email') {
 return new EmailNotification();
 }

 if ($type === 'sms') {
 return new SmsNotification();
 }

 if ($type === 'push') {
 return new PushNotification();
 }

 throw new InvalidArgumentException('Unknown type');
 }
}
Если добавился, например,
Telegram
, то привет новый
if
:
if ($type === 'telegram') { 
 return new TelegramNotification(); 
}
Здесь мы упираемся в главную проблему такой реализации: фабрика знает обо всех возможных типах уведомлений.
Email
,
SMS
,
Push
,
Telegram
— все эти варианты собираются в одном месте.
Пока типов мало, это кажется удобным. Но с ростом фабрика превращается в список условий: она уже не просто создаёт объекты, а становится центральной точкой, которую приходится редактировать при каждом новом бизнес-требовании.
Что с этим можно сделать? Для начала добавим интерфейс для уведомлений:
interface Notification 
{ 
 public function send(): void; 
}
Далее опишем абстрактный класс для фабричного метода (в идеале еще и интерфейс добавить)
abstract class NotificationService
{ 
 abstract public function create(): Notification; 

 public function process(): void 
 { 
 $notification = $this->create(); 
 $notification->send(); 
 } 
}
Далее унаследуем каждый сервис от этого класса
class EmailService extends NotificationService
{ 
 public function create(): Notification 
 { 
 return new EmailNotification(); 
 } 
}
class SmsService extends NotificationService 
{ 

 public function create(): Notification 
 { 
 return new SmsNotification(); 
 } 
}
Добавился
Telegram
? Не проблема:
class TelegramService extends NotificationService
{
 public function create(): Notification
 {
 return new TelegramNotification();
 }
}
Обратите внимание, что при появлении
Telegram
нам больше не нужно открывать и изменять
EmailService
или
SmsService
. Мы просто добавляем новый класс
TelegramService
. Старые классы при этом остаются неизменными. Именно в этом практический смысл
OCP
: новая возможность появляется через расширение системы, а не через постоянное редактирование уже работающего кода.
Тут встает закономерный вопрос: В чём смысл этих фабрик, если в конечном итоге придётся делать выбор нужной фабрики:
$type = $_POST['CLIENT_NOTIFICATION_SERVICE'] ?? '';
$service = null;

if ($type === 'email') {
 $service = new EmailService();
} elseif ($type === 'sms') {
 $service = new SmsService();
} elseif ($type === 'telegram') {
 $service = new TelegramService();
} else {
 throw new InvalidArgumentException('Unknown type');
}

$service->process();
Это справедливый вопрос, потому что выбор реализации действительно никуда не исчезает. Если пользователь передал строку
email
,
sms
или
telegram
, приложение все равно должно понять, какой сервис использовать.
Но важно, где именно происходит этот выбор. Если держать его внутри фабрики, её приходится менять при каждом новом типе уведомлений. Вместо этого можно вынести выбор в отдельное место сборки приложения.
Вот один из простых вариантов: сделать
NotificationCenter
, который будет работать как реестр доступных сервисов.
class NotificationCenter 
{ 
 /** @var array<string, NotificationService> */
 private array $services = []; 

 public function register(string $type, NotificationService $service): void 
 { 
 $this->services[$type] = $service; 
 } 

 public function send(string $type): void
 {
 if (!isset($this->services[$type])) {
 throw new InvalidArgumentException("Unknown type: $type");
 }

 $this->services[$type]->process();
 }
}
Тогда наш вышеприведённый код будет выглядеть примерно так:
$notificationCenter = new NotificationCenter();
$notificationCenter->register('email', new EmailService());
$notificationCenter->register('sms', new SmsService());
$notificationCenter->register('telegram', new TelegramService());
$type = $_POST['CLIENT_NOTIFICATION_SERVICE'] ?? '';
$notificationCenter->send($type);
Такой подход часто называют реестром объектов: мы заранее регистрируем доступные реализации, а потом выбираем нужную по ключу. Главное отличие от исходной фабрики в том, что логика отправки уведомлений больше не смешана со списком всех возможных типов. Новый канал уведомлений добавляется через новый сервис и регистрацию, а не через правку большого метода
create()
.
Выбор реализации все равно где-то должен произойти. Вопрос не в том, чтобы магически избавиться от выбора, а в том, чтобы вынести его из бизнес-кода в место сборки приложения: конфигурацию, DI-контейнер или
registry
. Тогда добавление нового типа уведомлений будет требовать добавления нового класса и регистрации в одном предсказуемом месте, а не правки уже существующей фабрики с бизнес-логикой.
При этом не стоит превращать
OCP
в религию. Если вариантов два, они редко меняются, а фабрика находится в одном месте и не расползается по проекту, простой
match/if
может быть нормальным решением. Проблема начинается, когда список типов расширяется регулярно, а фабрика становится точкой, которую приходится править при каждом новом бизнес-сценарии.
То есть важен не формальный запрет на
if
,
switch
или
match
. Важен вопрос: как часто этот код будет меняться и насколько безопасно его менять. То есть важно не то, что вы выбрали, а пониманий последствий этого выбора.
Если фабрика обслуживает стабильный набор вариантов, простое условие может быть нормальным решением. Если же новые типы появляются регулярно, то центральная фабрика быстро превращается в узкое место архитектуры.
Почему проблема выходит за рамки учебных статей
Это важно, потому что плохие примеры не остаются только в одной статье. На них учатся люди, их пересказывают на собеседованиях, копируют в рабочий код, а теперь ещё и получают от ИИ по запросу.
LLM-модели часто воспроизводят не самый архитектурно точный вариант, а самый узнаваемый и распространённый. Если в обучающих материалах фабрикой постоянно называют метод
create($type)
с набором
if
/
elseif
, то похожий код легко получить как «пример паттерна
Factory Method
».
Например, можно дать такой промт:
Напиши на PHP пример паттерна
Factory Method
для создания уведомлений: email, sms и push. Пользователь должен передавать строковый тип уведомления, а фабрика должна возвращать нужный объект.
С большой вероятностью ответ будет выглядеть примерно так:
class NotificationFactory
{
 public function create(string $type): Notification
 {
 return match ($type) {
 'email' => new EmailNotification(),
 'sms' => new SmsNotification(),
 'push' => new PushNotification(),
 default => throw new InvalidArgumentException('Unknown notification type'),
 };
 }
}
На первый взгляд код выглядит нормально: он короткий, понятный и даже использует match. Но архитектурная проблема никуда не делась. Если, например, появится
Telegram
, нам снова придется открыть
NotificationFactory
и добавить новую ветку. Значит, класс закрыт для расширения только на словах, а на практике открыт для постоянных изменений.
Чтобы получить более осмысленный пример, промт лучше формулировать сразу с архитектурным ограничением:
Напиши на
PHP
пример создания уведомлений без нарушения
OCP
. Новые типы уведомлений должны добавляться через новые классы и регистрацию в контейнере или
registry
, без изменения существующей фабрики.
Такой промт не гарантирует идеальный ответ, но хотя бы направляет ИИ в сторону нужной архитектурной идеи: новый тип добавляется через новый класс и регистрацию, а не через правку центрального
match
.
Как проблема становится заметна в реальном проекте
Отдельная проблема появляется, когда пример из статьи пытаются перенести в реальный проект. В учебном коде объект обычно создается просто через
new EmailNotification()
. Но в рабочем приложении почти любой сервис зависит от других компонентов.
В реальных проектах уведомления почти всегда имеют зависимости. Например,
email
-уведомлению может понадобиться mailer и шаблонизатор:
class EmailService extends NotificationService
{
 public function __construct(
 private Mailer $mailer,
 private TemplateRenderer $renderer,
 ) {}

 public function create(): Notification
 {
 return new EmailNotification($this->mailer, $this->renderer);
 }
}
Из-за таких зависимостей подход «просто создать класс по строке» быстро превращается в комок ручной сборки объектов. Во фреймворках
Symfony
/
Laravel
это обычно решается через DI-контейнер: tagged services, service providers, container binding или конфигурационный map. Можно сделать совсем просто: сложить в какой-нибудь конфигурационный файл массив, а в него добавлять классы, после чего вызывать
$array['sms']->process()
. Такой подход имеет ряд минусов, но для быстрого решения вполне годится.
Что использовать в итоге
Иногда
if
,
switch
или
match
— нормальное и понятное решение, отказываться от них не стоит.
Проблема начинается не там, где в коде появился
match
, а там, где этот
match
приходится менять при каждом новом сценарии. Если система растет, появляются новые типы уведомлений, новые зависимости и новые правила, стоит задуматься о более расширяемой архитектуре.
Паттерны проектирования полезны не потому, что позволяют писать единственно правильный код. Они полезны, когда помогают подготовить систему к изменениям. Поэтому любой пример фабрики стоит оценивать не по тому, насколько он короткий, а по тому, что произойдет, когда в систему придёт новый тип объекта.

Визуальный стек статейного сайта складывается из сотен мелких решений — от оси GRAD в шрифте до длительности анимации закрытия модального окна. Каждое такое решение либо работает на чтение, либо ворует внимание у текста.
Почему один шрифтовой файл заменяет целое семейство начертаний
Разработчики обычно ограничиваются двумя параметрами: размером шрифта и межстрочным интервалом. Такой подход остаётся точкой входа, но не раскрывает возможностей современных шрифтовых технологий.
Переменный шрифт представляет собой не набор статичных начертаний, а непрерывное пространство параметров. Inter Variable, к примеру, поддерживает ось wght для управления весом от 100 до 900 и ось opsz для оптического размера, который автоматически подстраивает форму глифов под кегль. Некоторые шрифтовые семейства добавляют ось GRAD — grade, которая меняет визуальную плотность символа без изменения его ширины. Связка этих осей позволяет точно настраивать типографику под конкретные условия отображения, не загружая отдельные файлы для каждого начертания.
body {
 font-family: 'Inter Variable', sans-serif;
 font-variation-settings: 'wght' 400, 'opsz' 32;
}

h1 {
 font-variation-settings: 'wght' 750, 'opsz' 72, 'GRAD' 0;
}
На тёмном фоне буквы воспринимаются визуально жирнее из-за эффекта irradiation — светлое на тёмном «расплывается» в сторону фона. Ось
GRAD
позволяет компенсировать это без изменения геометрии глифов:
@media (prefers-color-scheme: dark) {
 body { font-variation-settings: 'wght' 400, 'opsz' 32, 'GRAD' -25; }
}
Fluid-шкала вместо брейкпоинтов
Типографическая шкала через
clamp()
задаёт непрерывный поток вместо дискретных скачков на медиазапросах. Каждое значение описывает минимум на узком вьюпорте, скорость роста через
vw
и максимум на широком:
:root {
 --step--1: clamp(0.75rem, 0.7rem + 0.25vw, 0.875rem);
 --step-0: clamp(1rem, 0.95rem + 0.25vw, 1.125rem);
 --step-1: clamp(1.2rem, 1.1rem + 0.5vw, 1.5rem);
 --step-2: clamp(1.44rem, 1.25rem + 1vw, 2rem);
 --step-3: clamp(1.728rem, 1.4rem + 1.5vw, 2.5rem);
 --step-4: clamp(2.074rem, 1.6rem + 2.5vw, 3.5rem);
}
Коэффициент роста между ступенями (~1.2) сохраняет музыкальность шкалы на любом размере экрана без ручной синхронизации значений.
OpenType-функции
Шрифты с поддержкой OpenType содержат альтернативные глифы, которые по умолчанию выключены. Включение требует явного указания:
.article-body {
 font-feature-settings:
 'kern' 1, /* кернинг */
 'liga' 1, /* стандартные лигатуры: fi, fl */
 'calt' 1, /* контекстные альтернативы */
 'onum' 1; /* строчные цифры — не торчат выше строки */
}

/* Только в таблицах и метаданных: */
.data-table, .post-meta {
 font-feature-settings: 'tnum' 1; /* табличные цифры — одинаковая ширина */
}
onum
(oldstyle numerals) — принципиальная деталь для длинного читательского текста. Заглавные цифры (0–9 стандартные) визуально выпирают из строки, строчные интегрируются в ритм текста.
Оптическое выравнивание заголовков
Из-за боковых полей глифов заголовки с засечками или геометрическими шрифтами кажутся «съехавшими» вправо относительно начала колонки. Компенсация:
h1, h2, h3 {
 text-indent: -0.05em;
 hanging-punctuation: first last;
}
hanging-punctuation
выносит кавычки и тире за поле колонки — так оптическая граница совпадает с геометрической.
Иерархия prose-блоков
Статья содержит несколько типов блоков с разной функцией. Назначение каждому собственного размерного токена делает иерархию явной и легко корректируемой без правки каждого блока отдельно:
:root {
 --sbrd-single-body: 1.0rem; /* основной текст */
 --sbrd-single-quote: 0.93rem; /* цитата — тише body */
 --sbrd-single-list: 0.90rem; /* списки — вспомогательный слой */
 --sbrd-single-disclaimer: 0.84rem; /* служебный блок */
 --sbrd-single-code: 0.875rem;
}
Ключевое соотношение:
body > quote > list > disclaimer
. Нарушение этой иерархии — когда список совпадает по размеру с основным текстом — создаёт ощущение «двух конкурирующих потоков» вместо структурированного чтения.
Цвет: перцептивная система на OKLCH
Почему не HSL
Модель HSL оперирует математической геометрией, игнорируя физиологию человеческого зрения. При равных значениях параметра яркости желтый и синий цвета будут казаться глазу совершенно разными по светлоте, причем желтый всегда выглядит значительно светлее. Пространство OKLCH устраняет этот перекос, выравнивая цветовые координаты под реальное восприятие. Равные цифры светлоты в данной системе гарантируют, что любые оттенки считываются как одинаково яркие, что позволяет строить визуально сбалансированные интерфейсные палитры.
Это принципиально для систем состояний — success, warning, danger, info:
:root {
 --state-success: oklch(65% 0.18 145); /* зелёный */
 --state-warning: oklch(75% 0.18 85); /* янтарный */
 --state-danger: oklch(62% 0.22 25); /* красный */
 --state-info: oklch(65% 0.18 250); /* синий */
}
При фиксированном
L
и сопоставимом
C
все четыре цвета воспринимаются одинаково «loud» — ни один не доминирует над другим только за счёт яркости.
Relative color syntax
CSS Relative Color Syntax позволяет строить производные от базового токена математически, без ручного подбора значений:
:root {
 --accent: oklch(65% 0.2 250);

 --accent-light: oklch(from var(--accent) calc(l + 0.15) c h);
 --accent-dark: oklch(from var(--accent) calc(l - 0.15) c h);
 --accent-muted: oklch(from var(--accent) l calc(c * 0.4) h);
 --accent-complement: oklch(from var(--accent) l c calc(h + 180));

 --accent-10: oklch(from var(--accent) l c h / 0.10);
 --accent-20: oklch(from var(--accent) l c h / 0.20);
}
При изменении
--accent
все производные пересчитываются автоматически. Это исключает ситуацию, когда смена акцентного цвета требует ручного обновления десятков переменных.
Три уровня токенов
Хорошо организованная система строится от примитивов к семантике и от семантики к компонентам:
/* Уровень 1 — примитивы, не используются напрямую */
--blue-500: oklch(55% 0.18 250);
--gray-950: oklch(10% 0.01 250);

/* Уровень 2 — семантика */
--color-bg-primary: var(--gray-950);
--color-text-primary: var(--gray-50);
--color-text-secondary:var(--gray-400);
--color-border-subtle: var(--gray-800);

/* Уровень 3 — компоненты */
--article-bg: var(--color-bg-primary);
--callout-border: var(--color-border-default);
Компоненты никогда не ссылаются на примитивы напрямую. Это гарантирует, что при смене темы достаточно переопределить семантический слой.
Контраст как инструмент иерархии
WCAG задаёт минимальную планку. Реальная задача контраста — создать визуальную иерархию, при которой взгляд читателя двигается по странице предсказуемо:
Основной текст статьи ~12:1 максимальная читаемость
Комментарии ~8:1 важно, но вторично
Метаданные (дата, счёт) ~5:1 сканируется
Плейсхолдеры ~3.5:1 намёк, не контент
Декоративные границы ~2:1 структура без акцента
Использование одного уровня контраста для всех элементов — это визуальный шум. Иерархия контраста равна иерархии внимания.
Поверхности и пространство
Surface ladder
Глубина темного интерфейса создаётся не тенями (они теряют смысл на тёмном фоне), а последовательным осветлением слоёв:
--surface-0: oklch(12% 0.01 250); /* страница */
--surface-1: oklch(15% 0.01 250); /* карточки */
--surface-2: oklch(18% 0.015 250); /* поднятые элементы */
--surface-3: oklch(22% 0.02 250); /* hover */
--surface-4: oklch(26% 0.02 250); /* активные состояния */
Каждый слой отличается от предыдущего примерно на
3%
по
L
. Это создаёт воспринимаемую глубину без резких переходов. Ключевое:
surface-0
— это фон страницы, а не самый тёмный элемент.
Тёмная тема: специфические ловушки
Размещение блоков чистого белого цвета (#ffffff) на глубоком тёмном фоне (#080b0f) формирует зоны экстремального контраста. Человеческий глаз адаптируется к общему уровню освещённости интерфейса. Резкие перепады яркости вызывают эффект гало и быструю утомляемость. Формируйте поднятые карточки и модальные окна исключительно через токены поверхностных слоёв (--surface-1, --surface-2). Прямое указание
background: white
в стилях компонентов исключите полностью.
Насыщенность (chroma) акцентных оттенков на тёмном фоне требует принудительного снижения. Применение максимально яркого синего
oklch(65% 0.25 250)
на подложке
oklch(12%)
провоцирует оптическую вибрацию. Светлый и тёмный цвета начинают конкурировать за фокус, создавая ложные границы и мерцание на стыке. Ограничьте рабочий диапазон насыщенности на тёмной подложке значениями 0.15–0.20. Превышение указанного порога неизбежно генерирует визуальный шум.
Атмосфера: детали которые не копируются одной строкой
Noise texture
Плоский заливной цвет выглядит дёшево на высококачественных экранах. Тонкий зернистый слой добавляет материальность, имитируя физическую текстуру:
.article-hero::after {
 content: '';
 position: absolute;
 inset: 0;
 background-image: url("data:image/svg+xml,%3Csvg viewBox='0 0 256 256' xmlns='http://www.w3.org/2000/svg'%3E%3Cfilter id='noise'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='0.9' numOctaves='4' stitchTiles='stitch'/%3E%3C/filter%3E%3Crect width='100%25' height='100%25' filter='url(%23noise)' opacity='0.04'/%3E%3C/svg%3E");
 pointer-events: none;
}
opacity: 0.04
— работающий диапазон. Ниже — незаметно, выше — становится артефактом.
Gradient mesh
Многоточечный градиентный фон за заголовком создаёт глубину без тяжёлых изображений:
.article-header__mesh {
 position: absolute;
 inset: -50%;
 background:
 radial-gradient(ellipse 60% 50% at 20% 50%,
 oklch(55% 0.2 280 / 0.15) 0%, transparent 70%),
 radial-gradient(ellipse 50% 60% at 80% 30%,
 oklch(60% 0.18 200 / 0.12) 0%, transparent 70%);
 filter: blur(60px);
 animation: mesh-drift 20s ease-in-out infinite alternate;
 pointer-events: none;
}

@keyframes mesh-drift {
 0% { transform: translate(0, 0) scale(1); }
 50% { transform: translate(2%, 1%) scale(1.02); }
 100% { transform: translate(1%, -1%) scale(1.01); }
}
blur(60px)
делает переходы между пятнами мягкими.
inset: -50%
— обёртка больше контейнера, чтобы размытые края не обрезались.
Scroll-driven animations: CSS без JavaScript
Прогресс чтения
Прогресс-бар как анимация, привязанная к скроллу корневого элемента:
@keyframes progress {
 from { width: 0%; }
 to { width: 100%; }
}

.reading-progress {
 position: fixed;
 top: 0; left: 0;
 height: 2px;
 background: var(--accent);
 animation: progress linear both;
 animation-timeline: scroll(root);
}
Появление элементов
view()
timeline привязывает анимацию к вхождению элемента в вьюпорт:
.article-body > * {
 animation: fade-up linear both;
 animation-timeline: view();
 animation-range: entry 0% entry 30%;
}

@keyframes fade-up {
 from { opacity: 0; transform: translateY(24px); filter: blur(4px); }
 to { opacity: 1; transform: translateY(0); filter: blur(0); }
}
animation-range: entry 0% entry 30%
— анимация завершается, когда элемент прошёл 30% от нижней границы вьюпорта. После этого элемент остаётся полностью видимым.
Reduced motion
При
prefers-reduced-motion: reduce
движение отключается, но контент не исчезает — только fade:
@media (prefers-reduced-motion: reduce) {
 .article-header__mesh { animation: none; }

 .article-body > * {
 animation: fade-in linear both;
 animation-timeline: view();
 animation-range: entry 0% entry 20%;
 }
 @keyframes fade-in {
 from { opacity: 0; }
 to { opacity: 1; }
 }
}
Комьюнити-слой: визуальная система
Комьюнити-элементы живут поверх контента. Их цветовая логика не должна конкурировать с текстом статьи — комьюнити всегда вторично по вниманию.
Аватары: детали которые замечают
Вместо белой рамки — свечение цвета самого аватара. Это технически сложнее, но визуально корректнее: рамка отделяет, свечение интегрирует:
.avatar {
 width: 36px; height: 36px;
 border-radius: 50%;
 flex-shrink: 0;
 box-shadow:
 0 0 0 2px var(--surface-1),
 0 0 0 3px oklch(from var(--user-color) l c h / 0.4);
}
Цвет аватара генерируется детерминированно из имени пользователя — одинаковое имя всегда даёт одинаковый цвет:
function userColor(username) {
 let hash = 0;
 for (let i = 0; i < username.length; i++) {
 hash = username.charCodeAt(i) + ((hash << 5) - hash);
 }
 const hue = Math.abs(hash) % 360;
 return `oklch(65% 0.18 ${hue})`;
}
Фиксированные
L
и
C
при переменном
H
гарантируют, что все сгенерированные цвета одинаково яркие — никто не получает «страшно тёмный» или «слепящий» аватар.
Стек аватаров раздвигается при наведении:
.avatar-stack .avatar { margin-left: -10px; transition: margin 0.2s ease; }
.avatar-stack:hover .avatar { margin-left: 4px; }
.avatar-stack .avatar:hover { z-index: 10; transform: translateY(-2px) scale(1.1); }
Форма комментария: живые состояния
Форма существует минимум в трёх состояниях, каждое из которых должно ощущаться физически отличным:
Покой
— нейтральный
--surface-1
, тонкая граница.
Взаимодействие
— при
:focus-within
граница переходит в акцентный цвет, фон поднимается до
--surface-2
, появляется glow, тулбар с действиями въезжает снизу:
.comment-form:focus-within {
 border-color: var(--border-focus);
 background: var(--surface-2);
 box-shadow:
 0 0 0 3px var(--glow-focus),
 0 8px 24px rgb(0 0 0 / 0.15);
}

.comment-form__toolbar {
 opacity: 0;
 transform: translateY(4px);
 transition: opacity 0.2s ease, transform 0.2s ease;
}

.comment-form:focus-within .comment-form__toolbar {
 opacity: 1;
 transform: translateY(0);
}
field-sizing: content
на textarea позволяет полю расти с контентом без JavaScript:
.comment-textarea {
 field-sizing: content;
 min-height: 80px;
 max-height: 400px;
 resize: none;
}
Счётчик символов меняет цвет при приближении к лимиту через data-атрибуты — это разделяет логику состояния и его визуализацию:
.char-counter[data-warning='true'] { color: var(--state-warning); }
.char-counter[data-danger='true'] { color: var(--state-danger); }
Кнопки: три варианта
Primary
— заливка акцентным цветом, тёмный текст поверх, при hover поднимается и светлеет:
.btn--primary:hover {
 background: oklch(from var(--accent) calc(l + 0.05) c h);
 box-shadow: 0 4px 12px oklch(from var(--accent) l c h / 0.4);
 transform: translateY(-1px);
}
Ghost
— без заливки, только граница. При hover фон появляется — не наоборот.
Danger
— скрытая угроза: в покое не выглядит опасной, только при наведении проявляет красный фон. Это снижает тревожность от нейтрального UI, сохраняя сигнал при намеренном взаимодействии.
Состояние загрузки через
aria-busy
без изменения разметки:
.btn[aria-busy='true'] { pointer-events: none; opacity: 0.7; }
.btn[aria-busy='true'] .btn__text { opacity: 0; }
.btn[aria-busy='true']::before {
 content: '';
 position: absolute;
 width: 16px; height: 16px;
 border: 2px solid currentColor;
 border-top-color: transparent;
 border-radius: 50%;
 animation: spin 0.6s linear infinite;
}
Реакции на абзацы
Триггер появляется в gutter при наведении на абзац — не занимает места в основном потоке:
.reactions-trigger {
 position: absolute;
 left: -2.5rem;
 top: 50%;
 transform: translateY(-50%) scale(0.8);
 opacity: 0;
 transition: opacity 0.15s ease, transform 0.2s cubic-bezier(0.34, 1.56, 0.64, 1);
}

.paragraph-wrapper:hover .reactions-trigger {
 opacity: 1;
 transform: translateY(-50%) scale(1);
}
Пружинная кубическая кривая
cubic-bezier(0.34, 1.56, 0.64, 1)
— spring easing. Значения
>1
по
y
создают небольшой overshooting, иммитирующий физическую упругость. Это отличает UI от «планшетного» равномерного движения.
Попап с эмодзи появляется от триггера с тем же spring:
.reaction-emoji:hover {
 transform: scale(1.3) translateY(-2px);
 background: var(--surface-3);
}
Микроанимации: каждая решает задачу
Каждая анимация в хорошем UI несёт информацию — не декоративна.
Появление нового комментария
сообщает: «этого здесь не было».
blur
при появлении акцентирует переход из несуществующего состояния в существующее:
@keyframes comment-appear {
 from { opacity: 0; transform: translateY(12px); filter: blur(2px); }
 to { opacity: 1; transform: translateY(0); filter: blur(0); }
}
Удаление
схлопывает элемент — пространство не остаётся пустым резко:
@keyframes comment-remove {
 to { opacity: 0; transform: translateX(-12px) scale(0.97); max-height: 0; margin: 0; padding: 0; }
}
Лайк
использует двухфазный bounce — сначала сжатие (антиципация), потом overshooting. Это имитирует физику нажатой кнопки:
@keyframes like-bounce {
 0% { transform: scale(1); }
 30% { transform: scale(0.8); }
 60% { transform: scale(1.35); }
 80% { transform: scale(0.95); }
 100% { transform: scale(1); }
}
Скелетон
вместо спиннера — shimmer повторяет форму будущего контента, снижая воспринимаемое время ожидания:
@keyframes skeleton-shimmer {
 from { background-position: -200% 0; }
 to { background-position: 200% 0; }
}

.skeleton {
 background: linear-gradient(90deg,
 var(--surface-1) 0%, var(--surface-3) 50%, var(--surface-1) 100%);
 background-size: 200% 100%;
 animation: skeleton-shimmer 1.5s ease infinite;
}
Счётчик лайков
прокручивается как слот-машина — новое число въезжает снизу, старое уезжает вверх. Это делает изменение заметным без цветового сигнала:
.like-count { display: inline-block; overflow: hidden; height: 1.2em; }
.like-count__inner { display: flex; flex-direction: column; transition: transform 0.3s cubic-bezier(0.34, 1.56, 0.64, 1); }
.like-count__inner.increment { transform: translateY(-50%); }
Онлайн-индикатор
пульсирует с помощью расширяющегося box-shadow — не мигает, что раздражает, а «дышит»:
@keyframes online-pulse {
 0%, 100% { box-shadow: 0 0 0 0 oklch(65% 0.18 145 / 0.6); }
 50% { box-shadow: 0 0 0 4px oklch(65% 0.18 145 / 0); }
}
Toast-уведомления
содержат прогресс-бар автозакрытия — пользователь видит, сколько времени осталось:
.notification::after {
 content: '';
 position: absolute;
 bottom: 0; left: 0;
 height: 2px;
 background: var(--notification-color, var(--accent));
 animation: notification-timer var(--duration, 5s) linear forwards;
}

@keyframes notification-timer {
 from { width: 100%; }
 to { width: 0%; }
}
Модальные окна
backdrop-filter: blur
на подложке создаёт эффект «стекла» — контент под модалкой виден, но вторичен. Это важно: blur сообщает пользователю, что он находится в другом слое, а не что фон исчез:
.modal-backdrop {
 backdrop-filter: blur(8px);
 background: rgb(0 0 0 / 0.6);
}

.modal {
 animation: modal-appear 0.3s cubic-bezier(0.34, 1.56, 0.64, 1) both;
}

@keyframes modal-appear {
 from { opacity: 0; transform: scale(0.94) translateY(8px); }
 to { opacity: 1; transform: scale(1) translateY(0); }
}
Закрытие — отдельная анимация, быстрее появления. Это интуитивно: пользователь хочет вернуться к контенту быстро.
Архитектура CSS: @layer против войны специфичности
Каскадные слои делают порядок применения правил явным:
@layer reset, base, tokens, layout, components, utilities, overrides;
Правило в
utilities
всегда перекроет
components
независимо от специфичности селекторов. Это устраняет
!important
-войны и делает переопределения предсказуемыми. Компоненты комьюнити должны жить в одном слое с компонентами статьи — не в отдельном
@layer
поверх, иначе создаётся своя точка конфликта.
Доступность как часть системы
Focus visible
— не браузерный default:
:focus-visible {
 outline: 2px solid var(--accent);
 outline-offset: 3px;
 border-radius: 4px;
}

:focus:not(:focus-visible) { outline: none; }
Второе правило убирает outline при клике мышью — focus-стиль нужен клавиатурным пользователям, а не всем подряд.
Touch targets
— минимум 44×44 пикселей на mobile для кнопок реакций. Кнопки меньшего размера — это не экономия пространства, это ошибки пользователей.
ARIA
—
aria-busy
на кнопках в loading-состоянии, live regions для toast-уведомлений и новых комментариев. Скринридер должен объявлять об изменениях, которые произошли без действия пользователя.
Безопасность комьюнити-функций
Визуальный слой комьюнити-функций работает только до тех пор, пока система не сталкивается с реальным трафиком. Как только на сайте появляются реакции, голосования и комментарии, включаются автоматизированные сценарии. Защита здесь строится не на сложных алгоритмах, а на понимании того, как именно работают боты и уязвимые парсеры.
Лимиты по IP вместо сессий
Настройка ограничений только по сессии — это иллюзия защиты. Скрипту не составляет труда генерировать новую сессию каждые пять секунд, просто очищая куки. Если вы ограничиваете частоту реакций или голосов по сессии, бот обойдёт лимит за минуту. Привязка к IP-адресу усложняет задачу: сменить IP на лету без использования дорогой инфраструктуры прокси-серверов гораздо сложнее. Да, это не спасёт от крупного ботнета, но отсечёт 90% автоматизации, написанной на коленке.
Отпечатки браузера вместо cookies
Браузеры массово блокируют сторонние cookies. Полагаться на них при подсчёте голосов или блокировке спама бессмысленно — вы просто потеряете часть легитимных пользователей. Рабочая альтернатива — связка IP-адреса, User-Agent и временного окна. Если один и тот же браузер с одного адреса пытается проголосовать десять раз за десять минут, система блокирует действие. Хранить такой слепок дешевле, а для рядового пользователя, который просто открыл сайт в режиме инкогнито, это не создаст проблем.
Magic link вместо паролей
Отказ от паролей закрывает сразу несколько классов атак. Нет пароля — нечего украсть из базы при взломе, нечего подбирать брутфорсом, не нужно заставлять пользователей придумывать комбинации вроде
Qwerty123!
, которые они потом используют на банковских сайтах. Пользователь вводит email и получает ссылку с одноразовым токеном. Токен живёт 15–30 минут. Если письмо перехватят или аккаунт почты взломают постфактум, ссылка превратится в бесполезный набор символов.
Ловушка MD5 и хранение email
С хранением email связана частая ошибка. API сторонних сервисов, например Gravatar, требует передавать MD5-хеш адреса для подбора аватара. Разработчики по привычке сохраняют этот же MD5 в свою базу данных как идентификатор. MD5 для хранения учётных данных неприемлем: современные видеокарты перебирают такие хеши за секунды, а радужные таблицы лежат в открытом доступе. Для собственной базы используйте SHA-256 с солью или bcrypt. MD5 вычисляйте на лету только как временный буфер перед отправкой запроса к Gravatar, и сразу удаляйте из памяти.
Белые списки в Markdown
Чёрные списки запрещённых тегов в парсерах Markdown не работают. Вы заблокируете
<script>
, а злоумышленник воспользуется
<img src="x">
или вставит вредоносный код внутрь атрибутов SVG. Новые векторы атак появляются быстрее, чем вы успеваете обновлять чёрный список. Единственный рабочий подход — белый список. Парсер должен знать, что разрешены только
<b>
,
<i>
,
<a>
,
<code>
. Всё, чего нет в списке, безжалостно вырезается или экранируется. Система по умолчанию не знает о новых уязвимостях, поэтому и не может их отрендерить.
Премодерация первого комментария
На старте проекта нет смысла внедрять сложные ML-модели для поиска спама или платить за капчу. Самый дешёвый и эффективный метод — ручная премодерация первого комментария. Боты находят API эндпоинт и начинают спамить. Если первый пост от нового аккаунта уходит в очередь к модератору, а все последующие публикуются автоматически, вы отрезаете автоматизированные атаки. Один клик сотрудника модерации даёт пользователю доверие, и дальше он пишет свободно, не натыкаясь на искусственные барьеры.
Принцип: комьюнити не перебивает статью
Это не техническое требование — это продуктовый принцип. Пользователь пришёл читать. Комьюнити-элементы должны быть достаточно заметны, чтобы привлечь внимание при желании, и достаточно тихи, чтобы не мешать чтению.
Акцентный цвет комьюнити слабее, чем заголовки статьи. Анимации комьюнити не запускаются во время прокрутки статьи. Реакции на абзацы появляются в gutter, а не внутри текстовой колонки. Форма комментария находится после полного текста, а не между разделами.
Разница между обычным сайтом и выдающимся — не в наличии функций, а в плотности продуманных деталей на каждом уровне: от оси
GRAD
в шрифте до длительности анимации закрытия модального окна.
